args.cypher:
MATCH (aas:AAS) {-[:MANAGES_ASSET]-(asset)}
 RETURN aas.idShort, aas.id, asset.idShort
 WHERE asset.assetKind = 'Asset' OR aas.category = 'installs asset'

MATCH (sm:Submodel)
WHERE 'urn:submodel:mir100:type:nameplate' IN (sm.idShort)
OPTIONAL MATCH (sm)-[]{HAS_SEMANTIC_ID}

MATCH (ph:AssetAdministrationShell {idShort: "urn:aas:ur3e:001"}) {key: (ph)}
OPTIONAL MATCH (ph)
RETURN ph.idShort AS aasId, ph.id, sm.idShort AS submodelId

